USE P21;
SET NOCOUNT ON; SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
SELECT result_set='insert_transfer_hdr_modules', object_name=OBJECT_SCHEMA_NAME(m.object_id)+'.'+OBJECT_NAME(m.object_id), type_desc=o.type_desc, snippet=SUBSTRING(m.definition, CASE WHEN CHARINDEX('oe_transfer_reserve_flag',m.definition)>600 THEN CHARINDEX('oe_transfer_reserve_flag',m.definition)-600 ELSE 1 END, 3000)
FROM sys.sql_modules m JOIN sys.objects o ON o.object_id=m.object_id
WHERE m.definition LIKE '%INSERT%transfer_hdr%' AND m.definition LIKE '%oe_transfer_reserve_flag%'
ORDER BY object_name;
SELECT result_set='container_transfer_modules', object_name=OBJECT_SCHEMA_NAME(m.object_id)+'.'+OBJECT_NAME(m.object_id), type_desc=o.type_desc, snippet=SUBSTRING(m.definition, CASE WHEN CHARINDEX('container_receipts',m.definition)>600 THEN CHARINDEX('container_receipts',m.definition)-600 ELSE 1 END, 3000)
FROM sys.sql_modules m JOIN sys.objects o ON o.object_id=m.object_id
WHERE m.definition LIKE '%transfer_hdr%' AND m.definition LIKE '%container_receipts%'
ORDER BY object_name;
